      function CF_1Formula return Number is

V_CONDITION VARCHAR2(100);
V_COND_RET  VARCHAR2(5);
V_DISPLAY NUMBER(3);

begin
  IF :CONDITION IS NOT NULL THEN
  	V_CONDITION := :CONDITION ;
    IF INSTR(V_CONDITION,'=',1,1)>0 THEN
    	V_COND_RET := UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'=')+1,LENGTH(V_CONDITION))); 
    ELSIF INSTR(V_CONDITION,'<',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'<')+1,LENGTH(V_CONDITION))));      	
    ELSIF INSTR(V_CONDITION,'>',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'>')+1,LENGTH(V_CONDITION))));  
    ELSIF INSTR(V_CONDITION,'>=',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'>=')+2,LENGTH(V_CONDITION))));
    ELSIF INSTR(V_CONDITION,'<=',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'<=')+2,LENGTH(V_CONDITION))));    	   	
    END IF;
    
      V_DISPLAY := TO_NUMBER(V_COND_RET);
  END IF;
  RETURN V_DISPLAY;
end;

      function CF_2Formula return Char is
V_DISPLAY CHAR(10);
V_CHR_YEAR VARCHAR2(4);
V_CHR_DAY VARCHAR2(2);
V_CHR_MONTH VARCHAR2(2);
V_NUM NUMBER(4);
begin
  V_CHR_YEAR:=TO_CHAR(:P_INSURED_BIRTHDATE,'RRRR');
  V_CHR_DAY:=TO_CHAR(:P_INSURED_BIRTHDATE,'DD');
  V_CHR_MONTH:=TO_CHAR(:P_INSURED_BIRTHDATE,'MM');
  V_NUM:=TO_NUMBER(V_CHR_YEAR);
  V_NUM:=V_NUM+:CF_1;
  V_DISPLAY:=V_CHR_DAY||'/'||V_CHR_MONTH||'/'||V_NUM;
  RETURN V_DISPLAY;
end;

      function CF_3Formula return Number is

V_CONDITION VARCHAR2(100);
V_COND_RET  VARCHAR2(5);
V_DISPLAY NUMBER(5);

begin
  IF :CONDITION1 IS NOT NULL THEN
  	V_CONDITION := :CONDITION1 ;
    IF INSTR(V_CONDITION,'=',1,1)>0 THEN
    	V_COND_RET := UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'=')+1,LENGTH(V_CONDITION))); 
    ELSIF INSTR(V_CONDITION,'<',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'<')+1,LENGTH(V_CONDITION))));      	
    ELSIF INSTR(V_CONDITION,'>',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'>')+1,LENGTH(V_CONDITION))));  
    ELSIF INSTR(V_CONDITION,'>=',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'>=')+2,LENGTH(V_CONDITION))));
    ELSIF INSTR(V_CONDITION,'<=',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'<=')+2,LENGTH(V_CONDITION))));    	   	
    END IF;
    
      V_DISPLAY := TO_NUMBER(V_COND_RET);
  END IF;
  RETURN V_DISPLAY;
end;

      function CF_4Formula return char is
  
  V_DISPLAY VARCHAR2(50);

begin
  
IF :PRODUCT_CODE='00001' THEN
	V_DISPLAY:='ΣΥΝΤΑΞΗΣ ΓΗΡΑΤΟΣ';
end if;
IF :PRODUCT_CODE='00002' THEN
	V_DISPLAY:='ΣΥΝΤΑΞΗΣ ΑΝΑΠΗΡΙΑΣ';
end if;
IF :PRODUCT_CODE='00003' THEN
	V_DISPLAY:='ΣΥΝΤΑΞΗΣ ΘΑΝΑΤΟΥ ΑΣΦΑΛΙΣΜΕΝΟΥ';
end if;
IF :PRODUCT_CODE='00004' THEN
	V_DISPLAY:='ΣΥΝΤΑΞΗΣ ΘΑΝΑΤΟΥ ΣΥΝΤΑΞΙΟΥΧΟΥ';
end if;

return v_display;
end;

      function M_4FormatTrigger return boolean is
begin

  -- Automatically Generated from Report Builder.
  if :P_PRODINST IN (6) 
  	AND (:MEDICAL_DISABILITY!=0
  	OR :PENSION_DISABILITY!=0
  	OR :DISABILITY_START_DATE!=0
  	OR :DISABILITY_END_DATE!=0
  	OR :SUM_INS_DAYS_QUAL_FINAL!=0)
  	THEN
    return (TRUE);
  ELSE
    return (FALSE);
 END IF;
end;

      function M_8FormatTrigger return boolean is
begin

  -- Automatically Generated from Report Builder.
  if (:SUM_HEAVY_DAYS_PER_PERIOD = '0')
  then
    return (FALSE);
  end if;

  return (FALSE);
end;

      function CF_7Formula return char is

V_DISPLAY           CHAR(7);
V_MONTH             NUMBER;
V_YEAR              NUMBER;
V_DAYS              NUMBER;
V_TMP_DAY           NUMBER;
v_prepare_days_code NUMBER;
v_notice_days       NUMBER;
V_LAST_DATE1        VARCHAR2(10);
V_LAST_DATE         VARCHAR2(10);
V_FACTITIOUS_MONTH  NUMBER;
V_FACTITIOUS_YEAR   NUMBER;
V_SF_DATE           DATE;

CURSOR FIND_LAST_DAYS IS
SELECT sum(PEN_INSURED_DAYS.INSURANCE_DAYS_CALC_FINAL),
       prepare_days_code,
       sum(notice_insurance_days) 
 	FROM PEN_INSURED_DAYS 
 WHERE PEN_INSURED_DAYS.ACC_ACCOUNT_NO= :P_ACC_ACCOUNT_NO
   AND PEN_INSURED_DAYS.INS_INSURED_ID= :P_INSURED_ID
   AND PEN_INSURED_DAYS.USE_FLG='1'
   AND PEN_INSURED_DAYS.INSURANCE_DAYS_CALC_FINAL IS NOT NULL
   AND YEAR=V_YEAR
   AND MONTH=V_MONTH
group by prepare_days_code;--,notice_insurance_days;

begin
	V_YEAR:=TO_NUMBER(TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MO1,'RRRR'));
	V_MONTH:=TO_NUMBER(TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MO1,'MM'));
	
	V_FACTITIOUS_YEAR:=TO_NUMBER(TO_CHAR(:P_FACTITIOUS_DATE,'RRRR'));
	V_FACTITIOUS_MONTH:=TO_NUMBER(TO_CHAR(:P_FACTITIOUS_DATE,'MM'));
	
	IF :FIRST_LHKSH_ASFALISHS IS NOT NULL THEN
		V_SF_DATE :=TO_DATE(:FIRST_LHKSH_ASFALISHS,'DD/MM/RRRR');
	ELSE
		V_SF_DATE:=NULL;
	END IF;
	
--COMBAT_DEBUGING(:P_INSURED_ID,'V_YEAR'||V_YEAR);
--COMBAT_DEBUGING(:P_INSURED_ID,'V_MONTH'||V_MONTH);	
	OPEN FIND_LAST_DAYS;
	FETCH FIND_LAST_DAYS INTO V_DAYS, v_prepare_days_code, v_notice_days;
	CLOSE FIND_LAST_DAYS;
	
	V_LAST_DATE1:=TO_CHAR(TO_DATE(1 || '/' ||V_MONTH || '/' || V_YEAR,'DD/MM/RRRR'));
	V_LAST_DATE:=TO_NUMBER(TO_CHAR(LAST_DAY(V_LAST_DATE1),'DD'));
	
	
  IF V_FACTITIOUS_YEAR= V_YEAR AND V_FACTITIOUS_MONTH=V_MONTH THEN
		IF V_SF_DATE IS NOT NULL THEN

			IF V_SF_DATE<=:P_FACTITIOUS_DATE THEN

				IF TO_CHAR(V_SF_DATE,'MM/RRRR')= TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR') THEN
					V_DISPLAY:=TO_CHAR(V_SF_DATE,'MM/RRRR');
				END IF;

				IF TO_CHAR(V_SF_DATE,'MM/RRRR')!= TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR') THEN

				  --IF TO_DATE(V_DAYS || '/' ||V_MONTH || '/' || V_YEAR,'DD/MM/RRRR')>:P_FACTITIOUS_DATE THEN
				  IF TO_DATE(/*V_DAYS || '/' */'1/'||V_MONTH || '/' || V_YEAR,'DD/MM/RRRR')>:P_FACTITIOUS_DATE THEN
				  
				  V_DISPLAY:=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR');
			    ELSE  		
			     -- V_DISPLAY:=	TO_CHAR(TO_DATE(V_DAYS || '/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
			     V_DISPLAY:=	TO_CHAR(TO_DATE(/*V_DAYS || '/' */'1/'||V_MONTH || '/' || V_YEAR),'MM/RRRR');
	        END IF;				
				END IF;				
			ELSE

				V_DISPLAY:=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR');
			END IF;
	  ELSE
      
			IF TO_DATE(/*V_DAYS || '/' */'1/'||V_MONTH || '/' || V_YEAR,'DD/MM/RRRR')>:P_FACTITIOUS_DATE THEN
			  V_DISPLAY:=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR');
			ELSE  		
			  V_DISPLAY:=	TO_CHAR(TO_DATE('1/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
	    END IF;
	  END IF;
	ELSE
	 
	  IF v_notice_days>25 THEN
		  IF V_DAYS<v_notice_days THEN
		    V_TMP_DAY:=ROUND((V_DAYS*V_LAST_DATE)/v_notice_days);
		    V_DISPLAY:=	TO_CHAR(TO_DATE(V_TMP_DAY || '/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
	    ELSE
		    V_DISPLAY:=TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MO1,'MM/RRRR');
	    END IF;
	  ELSE
		  IF V_DAYS<25 THEN
		    V_TMP_DAY:=ROUND((V_DAYS*V_LAST_DATE)/25);  --de xrisimopoieitai!
	         
		    V_DISPLAY:=	TO_CHAR(TO_DATE(1 || '/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
		  ELSE
		    V_DISPLAY:=TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MO1,'MM/RRRR');
	    END IF;
	  END IF;
	END IF;

	RETURN v_display;--to_char(:P_ACC_ACCOUNT_NO);
  
end;

      function CF_KRATHSH_ASTHENIASFormula return Char is
V_DISPLAY CHAR(500);

begin
  
  IF :UPD_FLG=1 THEN
    V_DISPLAY:='ΚΑΙ ΧΩΡΙΣ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ. ';
  ELSE
    IF  ( :CS_PERCENTAGE1 IS NOT NULL AND :CS_PERCENTAGE1 = 0 )
      THEN V_DISPLAY:='ΚΑΙ ΧΩΡΙΣ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ. ';
    ELSE  
        IF :CS_PERCENTAGE1 IS NOT NULL THEN
          V_DISPLAY:='ΚΑΙ ΜΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ '||:CS_PERCENTAGE1||'% .';
        END IF;
        IF :CS_PERCENTAGE1 IS NULL AND :CS_PERCENTAGE IS NOT NULL THEN
          V_DISPLAY:='ΚΑΙ ΜΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ '||:CS_PERCENTAGE||'% .';
        END IF;
        IF :CS_PERCENTAGE1 IS NULL AND :CS_PERCENTAGE IS NULL AND :CS_DEFAULT_PERC IS NOT NULL THEN
          V_DISPLAY:='ΚΑΙ ΜΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ '||:CS_DEFAULT_PERC||'% .';
        END IF;
    END IF;   
        
  END IF;
  RETURN V_DISPLAY;
  
end;

