      FUNCTION CF_PRESUMED_WAGEFormula RETURN NUMBER IS

v_amount NUMBER;


CURSOR cur_presumed IS 
SELECT A.PRESUMED_WAGES
FROM COM_CURRENT_PRESUMED_WAGES A
WHERE A.PREWAG_INSURANCE_CLASS = :INSURANCE_CLASS
AND A.FROM_DAILY_WAGES <= ROUND(NVL(:NOTICE_TOTAL_SALARY_TEAM,0)/NVL(:NOTICE_TOTAL_DAYS_TEAM,0),2)
AND (A.TO_DAILY_WAGES >= ROUND(NVL(:NOTICE_TOTAL_SALARY_TEAM,0)/NVL(:NOTICE_TOTAL_DAYS_TEAM,0),2)
		 OR NVL(:INSURANCE_CLASS,0) = 28)
AND A.EFFECTIVENESS_START_DATE <= TO_DATE('31'||'12'||:PERIOD_YEAR_TO_TEAM,'DD/MM/RRRR') 
ORDER BY A.EFFECTIVENESS_START_DATE DESC;


BEGIN
  
  IF NVL(:NOTICE_TOTAL_DAYS_TEAM,0)!= 0 AND :PERIOD_YEAR_TO_TEAM IS NOT NULL THEN 
	  OPEN cur_presumed;
	  FETCH cur_presumed
	  INTO v_amount;
	  IF cur_presumed%NOTFOUND THEN
	  		v_amount:=NULL;
	  END IF;		
	  CLOSE cur_presumed;
  ELSE
  	v_amount:=NULL;
  END IF;
  RETURN v_amount;
END;

