      FUNCTION CF_PROCCESS_IDFormula RETURN NUMBER IS

V_PROCESS_ID NUMBER;

CURSOR CUR_PROCESS IS
SELECT A.PROCESS_ID
FROM PEN_SUMMARIZATION_PER_INSURED A
WHERE A.INSURED_ID = :P_INSURED_ID
ORDER BY A.PROCESS_ID DESC;

