      function AfterPForm return boolean is

CURSOR C1 IS
SELECT COM_ORG_BRANCHES.BRANCH_NAME, PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE
  FROM REG_INSURED, 
       PEN_APPLICATION_INSTANCES, 
	     COM_ORG_BRANCHES, 
	     PEN_QC_PER_PRODINST, 
	     PEN_PRODUCT_PER_INSTITUTIONS,
	     PEN_PRODUCTS,
	     COM_PENSION_IKA_INSTITUTION
 WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE
   AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001'
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR
   AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID
   AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID
   AND PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST
   AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE
   AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE
   AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE
   AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE;

cursor c2 is
SELECT PEN_DECISION_INSTANCE.E_DEC_YEAR||'/'||PEN_DECISION_INSTANCE.E_DEC_NO||'*'   , PEN_DECISION_INSTANCE.E_DEC_NO   ,
			 qual_pension_right_date,
			 TO_CHAR(payment_end_date	,'DD/MM/YYYY')  payment_end_date,
			 EPIFILAKSI
  FROM pen_decision_instance
 where dt_decision_year = :P_DT_DECISION_YEAR
  and  dec_incr_seq_no  = nvl(:P_DEC_INCR_SEC_NO,:P_DEC_INCR_SEQ_NO)
  and  dt_dec_unit_code = :P_DT_DEC_UNIT_CODE;
  
  
cursor c_wrk is 
select a.dec_orgbra_code||' / '||a.dec_year||' / '||a.dec_sid 
from wrk_decisions a
where a.status   = '1'
and   a.pen_unit = :P_DT_DEC_UNIT_CODE
and   a.pen_year = :P_DT_DECISION_YEAR
and   a.pen_no   = :P_DEC_INCR_SEC_NO
;

l_subterm_ga   varchar2(250);
L_DEC_NO       VARCHAR2(1000);
L_EPIFILAKSI   VARCHAR2(15);
L_INST_CODE    varchar2(50);

cursor c_Fast_Track is
select count(1) cnt
from   pen_dec_fact_types_instance a
where  a.di_document_type_dec_coce_sr = '1'  
and    a.status 			                = '1'
and    a.ins_insured_id               = :p_insured_id 
and    a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and    a.di_decision_year_sr          = :p_dt_decision_year 
and    a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and    a.title_code                   = '04921'   
and    a.dec_fact_type_code           = '04921' 
and    a.value	                       = '4'   --- 4 -fast track / 2 -non fast track    
;

cursor c_anagnoriseis is
select count(1)
  from pen_ops.Pen_Decision_Instance pdin, 
       Wrk_In_Out wiou, 
       Wrk_Application wapp, 
       Web_Wrk_Appl_EFKA wwae,
       Web_Wrk_EFKA_Cont_Work wecw, 
       Pen_Auto_Ins_Hist paih
where pdin.PAI_PDTA_Application_Unit_Code = wiou.Protocol_Orgbra_Code
   and pdin.PAI_PDTA_Application_Year      = wiou.Protocol_Year
   and pdin.PAI_Application_Incr_Seq_No    = wiou.Protocol_No
   and wiou.Ref_Appl_SID                   = wapp.Appl_SID
   and wapp.Appl_Protocol_Orgbra_Code      = wwae.Appl_Protocol_Orgbra_Code
   and wapp.Appl_Protocol_Year             = wwae.Appl_Protocol_Year               
   and wapp.Appl_Protocol_No               = to_char(wwae.Appl_Protocol_No)
   and wecw.Appl_SID                       = wwae.Appl_SID
   and paih.Call_ID                        = wecw.WS_Iah_Call_ID
   and paih.RecType                        = 5
   and pdin.Status                         = '1'
   and pdin.dt_dec_unit_code               = :P_DT_DEC_UNIT_CODE
   and pdin.dt_decision_year               = :P_DT_DECISION_YEAR
   and pdin.dec_incr_seq_no	               = :P_DEC_INCR_SEC_NO
  ;
  
l_anagnoriseis number:=0;
   
begin
  
  OPEN  C1;
  FETCH C1 INTO :P_BRANCH_NAME, L_INST_CODE;
  CLOSE C1; 
  
  IF L_INST_CODE = '2' THEN :P_EPIKOURIKH := 1; END IF;
  
  open  c_wrk;
	fetch c_wrk into :P_WRK_DEC_NO;
	close c_wrk;

	
	open  c2;
	fetch c2 into :p_e_yyyyaa, L_DEC_NO, :P_QUAL_PENSION_RIGHT_DATE,  :p_end_date, L_EPIFILAKSI ; 
	close c2;
	
	
	if l_epifilaksi = '1' then
		:p_epifylaxi := 'Επιφυλασσόμεθα για τυχόν αναθεώρηση της παρούσας απόφασης μετά απο επανεξέταση στοιχείων της συνταξιοδοτικής σας περιπτώσης';
		              --  'προαιρετικής ασφάλισης ή και άλλων χρόνων της ασφαλιστικής σας ιστορίας σύμφωνα με την αίτησή σας.'||chr(10)||
		              --  'Σας παρακαλούμε να προσέλθετε στο αρμόδιο Υποκατάστημα κατόπιν ραντεβού για την ολοκλήρωση της διαδικασίας '||
		              --  'μαζί με τα απαραίτητα έγγραφα';
	end if;	
	
	--- 23/08/2022 ΟΤΑΝ ΕΚΔΙΔΟΝΤΑΙ ΑΥΤΟΜΑΤΟΠΟΙΗΜΕΝΕΣ ΑΠΟΦΑΣΕΙΣ ΜΕ ΑΝΑΓΝΩΡΙΣΕΙΣ ΘΑ ΕΜΦΑΝΙΖΕΤΑΙ ΣΥΓΚΕΚΡΙΜΕΝΟ ΚΕΙΜΕΝΟ ΣΤΟ ΔΙΑΤΑΚΤΙΚΟ -MAIL ΑΠΟ 22/08/2022 PDROUVAS+ΑΒΑΛΙΑΝ+ΑΜΕΤΑΧΑ
  open  c_anagnoriseis;
  fetch c_anagnoriseis into l_anagnoriseis;
  close c_anagnoriseis;
  

  if nvl(l_anagnoriseis,0) > 0 
  	then :P_anagnoriseis := 1; 
    else :P_anagnoriseis := 0;
  end if; 	
  
  if  nvl(:P_anagnoriseis,0) > 0 
    then :p_epifylaxi := 'Επιφυλασσόμεθα για την τροποποίηση της παρούσας απόφασης ως προς τον χρόνο ασφάλισης '||chr(10)||
                         ' που θα προκύψει απο την έκδοση αναγνωριστικής απόφασης, καθώς επίσης και για τον τρόπο '||chr(10)||
                         ' αποπληρωμής του νέου ασφαλιστικού χρόνου.';
  end if;	
	
	if :p_end_date is null or :p_end_date = '31/12/2222' 
		then :p_end_date := ' και για χρόνο αόριστο.';
	  else :p_end_date := ' έως και '||:p_end_date;
  end if;		
	if L_DEC_NO is not null then 
	   :p_e_yyyyaa :=	'*e-'||:p_e_yyyyaa;
	else
		 :p_e_yyyyaa := null;
	end if;	 
	
--	:P_insured_id_appear := chr(183)||:P_insured_id||chr(183);

/*	
	 PENPRN_PENSION_REDUCTION(:P_ACC_ACCOUNT_NO,
												 	  1,
												 	  :P_PRODINST,
												 	  :P_PAYMENT_START_DATE,
	                   				:p_MONTHS_200);     */

	open  c_Fast_Track;
	fetch c_Fast_Track into :P_FAST_TRACK;
	close c_Fast_Track;


	 IF nvl(:P_FAST_TRACK,0) > 0 OR nvl(:P_anagnoriseis,0) > 0 THEN
	    :p_nomoi := ' Τις διατάξεις του Ν.4387/2016, όπως ισχύουν, του Ν. 4670/2020 και τις διατάξεις του Ν. 4921/2022 άρθρα 48-54.'||chr(10)||
	      'Ο ασφαλισμένος είναι υποχρεωμένος να διατηρήσει, διαθέσιμα για έλεγχο, τα φυσικά παραστατικά που δεν έχει προσκομίσει στον e-ΕΦΚΑ, για χρονικό διάστημα δέκα (10) ετών απο την έναρξη ισχύος της παρούσας απόφασης από την έναρξη ισχύος του Ν. 4921/2022.' ;
	 ELSE            
	  	:p_nomoi := null;
	 END IF;
	 
	 
--	srw.message(100,'P_ACC_ACCOUNT_NO :'||:P_ACC_ACCOUNT_NO);	    
--	srw.message(100,'p_dt_dec_unit_code :'||:p_dt_dec_unit_code);    
--  srw.message(100,'p_dt_decision_year :'||:p_dt_decision_year);
--	srw.message(100,'p_dec_incr_sec_no_sr :'||:p_dec_incr_sec_no_sr);
  return (TRUE);
  
end;

